UPDATE avaliacoes SET briefing = 'Todo cálculo judicial começa aqui: números que precisam sair de um processo e virar valores defensáveis. Neste primeiro caso, você prova que domina os fundamentos que sustentam qualquer laudo. Assuma o caso e mostre que os primeiros passos já ficaram para trás.' WHERE id = '8c9be23a-82fb-4155-920b-67a510dbf08a';

