UPDATE avaliacoes SET briefing = 'Veredito final do curso. Um contrato de cheque especial completo espera o seu recálculo, do primeiro encargo à última diferença apurada. Aprovado aqui, você está pronto para assumir revisionais dessa modalidade com assinatura própria.' WHERE id = '1e619735-117c-4062-b8bd-86928027f7c0';

