UPDATE avaliacoes SET briefing = 'O caso final deste curso coloca um contrato de financiamento real na sua frente: recalcular do início ao fim, aplicando o critério correto e apurando a diferença. É o tipo de trabalho que paga honorários de verdade no mercado. Mostre que está pronto.' WHERE id = 'db7654ab-c0e7-4fb2-84f0-2cfd8a23b479';

