UPDATE avaliacoes SET briefing = 'Antes de discutir juros, um perito precisa ler o contrato como o banco lê. Cláusulas, encargos e itens que decidem uma revisional estão espalhados por dezenas de páginas. Neste primeiro caso, você prova que nenhum item relevante passa despercebido pelo seu olhar.' WHERE id = '3d2a1771-7083-4143-a6d1-4d60e99084fe';

