UPDATE avaliacoes SET briefing = 'Veredito final do curso. Capitalização de juros, modalidades de contrato e tudo que você atravessou até aqui se encontram neste caso. Aprovado, você conclui a formação que ensina a pensar como o banco pensa, e a encontrar o que o banco esconde.' WHERE id = 'bc131919-904f-4d25-833b-c322a52b0aed';

