UPDATE avaliacoes SET briefing = 'Um processo judicial pode ter centenas de páginas, mas o cálculo depende de meia dúzia de informações escondidas nelas. A síntese processual é a ferramenta que transforma esse caos em clareza. Neste caso, você prova que sabe montar a síntese que sustenta o cálculo inteiro.' WHERE id = 'c724c329-603f-4d60-8efe-8653ca539958';

