UPDATE avaliacoes SET briefing = 'O PJe-Calc é a ferramenta oficial da Justiça do Trabalho, e a liquidação de sentença é onde o perito trabalhista prova seu valor. Este caso final reúne os dois: dominar a ferramenta e entregar uma liquidação que resiste a qualquer impugnação.' WHERE id = 'b92a66e9-19be-428b-a379-6a4bae1f8f6c';

